import json
from openai import OpenAI

client = OpenAI()

# Agent: model decides what to do and executes without per-step approval
tools = [
    {
        "type": "function",
        "function": {
            "name": "write_file",
            "description": "Write content to a file",
            "parameters": {
                "type": "object",
                "properties": {
                    "path": {"type": "string"},
                    "content": {"type": "string"}
                },
                "required": ["path", "content"]
            }
        }
    },
    {
        "type": "function",
        "function": {
            "name": "run_tests",
            "description": "Run pytest on a file, return stdout",
            "parameters": {
                "type": "object",
                "properties": {"path": {"type": "string"}},
                "required": ["path"]
            }
        }
    }
]

def execute_tool(name: str, args: dict) -> str:
    if name == "write_file":
        with open(args["path"], "w") as f:
            f.write(args["content"])
        return "written"
    if name == "run_tests":
        import subprocess
        result = subprocess.run(["pytest", args["path"], "-q"], capture_output=True, text=True)
        return result.stdout + result.stderr

messages = [{"role": "user", "content": "Write a Python function to parse ISO 8601 dates with tests, save it to date_utils.py and test_date_utils.py, and run the tests."}]

while True:
    response = client.chat.completions.create(
        model="gpt-4o-mini", messages=messages, tools=tools
    )
    msg = response.choices[0].message
    messages.append(msg)
    if not msg.tool_calls:
        print(msg.content)   # agent reports completion
        break
    for call in msg.tool_calls:
        result = execute_tool(call.function.name, json.loads(call.function.arguments))
        messages.append({"role": "tool", "tool_call_id": call.id, "content": result})
# Files are written and tests run without any human approval between steps.

from unittest.mock import patch, MagicMock

def test_agent_researches_before_writing():
    call_order = []

    def mock_tool(name, args):
        call_order.append(name)
        if name == "search_web":
            return [{"title": "ISO 8601", "snippet": "The standard date format..."}]
        if name == "write_file":
            return "written"
        return {}

    with patch("my_module.execute_tool", side_effect=mock_tool):
        result = run_agent("Write a summary of ISO 8601 to summary.txt")

    # Agent should search BEFORE writing — verify the order
    assert call_order.index("search_web") < call_order.index("write_file"), \
        "Agent wrote before researching"

from enum import Enum

class PermissionLevel(Enum):
    AUTO = "auto"        # execute without asking
    CONFIRM = "confirm"  # ask user before executing
    DENY = "deny"        # never execute

TOOL_PERMISSIONS = {
    "search_web":      PermissionLevel.AUTO,
    "read_file":       PermissionLevel.AUTO,
    "write_file":      PermissionLevel.CONFIRM,
    "send_email":      PermissionLevel.CONFIRM,
    "delete_record":   PermissionLevel.CONFIRM,
    "rm_rf":           PermissionLevel.DENY,
}

def execute_tool_with_permission(name: str, args: dict):
    level = TOOL_PERMISSIONS.get(name, PermissionLevel.DENY)

    if level == PermissionLevel.DENY:
        return {"error": f"Tool {name} is not permitted"}

    if level == PermissionLevel.CONFIRM:
        print(f"Agent wants to call {name}({args})")
        confirm = input("Allow? [y/n]: ")
        if confirm.strip().lower() != "y":
            return {"status": "cancelled", "reason": "user declined"}

    return execute_tool(name, args)  # AUTO or confirmed CONFIRM

# This agent behaves as a copilot for write operations and as an agent for reads.
# The autonomy level is per-tool, not per-system.
